import React, { useState, useEffect } from 'react';
import { Menu, Segment, Transition } from 'semantic-ui-react';
import '../../App.css'

export default function Nav(props) {
    function capitalizeFirstLetter(string) {
        return string.charAt(0).toUpperCase() + string.slice(1);
      }

    const {
        navLinks,
        setCurrentLink,
        currentLink,
        contactSelected,
        setContactSelected
    } = props;

    useEffect(() => {
        document.title = `Stephon Smith| ${currentLink.name}`
    }, [currentLink])
    const styleOptions = {
        backgroundColor: '#001427',
        color: '#f7f7ff',
        textAlign: 'center'
    };

    const transitions = [
        'jiggle',
        'flash',
        'shake',
        'pulse',
        'tada',
        'bounce'
    ];

    const [menuState, setMenuState] = useState('Home');
    const [animationState, setAnimationState] = useState({
        animation: transitions[0],
        duration: 500,
        visible: true
    });

    const handleAnimation = () => {
        setAnimationState(
            {
                visible: false
            }
        )
    }
    useEffect(() => {
        const transitionSelected = Math.floor(Math.random() * 7)
        setAnimationState({
            animation: transitions[transitionSelected],
            duration: 700,
            visible: true
        })
    }, [animationState.visible])

    function handleMenuClick(e, { name }) {
        setMenuState(name);
        setContactSelected(false);
    }


    return (
    <Segment 
        inverted
        style={styleOptions}
    >
        <Menu 
            inverted 
            pointing 
            secondary
        >
            <Menu.Item name='myName'>
                <Transition
                    animation={animationState.animation}
                    duration={animationState.duration}
                    visible={animationState.visible}
                >
                    <span onClick={handleAnimation}>Stephon Smith</span>
                </Transition>
            </Menu.Item>
            {navLinks.map((link) => {
                console.log(link)
                return <Menu.Item
                    name={link.name}
                    active={menuState === link.name}
                    onClick={handleMenuClick}
                    className={`${currentLink === link.name && !contactSelected && 'navActive'}`}
                    key={link.name}
                 >
                    <span
                        onClick={() => {
                            setCurrentLink(link.name);
                            setContactSelected(false);
                        }}
                    >
                        {capitalizeFirstLetter(link.name)}
                    </span>
                </Menu.Item>
            })}        
            <Menu.Item
                name='contactMe'
                active={menuState === 'contactMe'}
                className={`${contactSelected && 'navActive'}`}
                onClick={() => handleMenuClick}
            >
                <span onClick={() => setContactSelected(true)}>Contact Me</span>
            </Menu.Item>
        </Menu>
    </Segment>
    )
}